# Example Terraform initialization for a GCP project
provider "google" {
  project = "your-project-id"
  region  = "us-central1"
}

resource "google_project_service" "apis" {
  for_each = toset([
    "bigquery.googleapis.com",
    "alloydb.googleapis.com",
    "compute.googleapis.com"
  ])
  service = each.key
}
The workflow mandates running `terraform plan` before `terraform apply` for all infrastructure changes.
